import{c as a,O as t,i,m as r}from"./chunks/framework.BWIk71Uc.js";const m=JSON.parse('{"title":"Collection Framework","description":"Core knowledge points of the Java Collection Framework including List, Set, Map, and Stream API.","frontmatter":{"title":"Collection Framework","description":"Core knowledge points of the Java Collection Framework including List, Set, Map, and Stream API.","date":"2026-05-29T00:00:00.000Z","tags":["Java"],"category":"knowledge","status":"draft","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"en/notes/java/collection.md","filePath":"en/notes/java/collection.md","lastUpdated":1780128182000}'),o={name:"en/notes/java/collection.md"};function n(l,e,s,d,c,h){return t(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1780012800000"},[...e[0]||(e[0]=[r('<h1 id="collection-framework" tabindex="-1">Collection Framework <a class="header-anchor" href="#collection-framework" aria-label="Permalink to “Collection Framework”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>This page organizes the key topics and learning notes for the Java Collection Framework. It covers commonly used collections like List, Set, and Map, along with iterators and the Stream API.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to “Learning Path”">​</a></h2><ul><li>Step 1: Understand the basic collection interfaces</li><li>Step 2: Read the core notes on implementations (ArrayList, HashMap, etc.)</li><li>Step 3: Connect the topic with real projects</li><li>Step 4: Review common pitfalls and interview questions</li></ul><h2 id="core-content" tabindex="-1">Core Content <a class="header-anchor" href="#core-content" aria-label="Permalink to “Core Content”">​</a></h2><h3 id="list" tabindex="-1">List <a class="header-anchor" href="#list" aria-label="Permalink to “List”">​</a></h3><ul><li>ArrayList: Array implementation, fast random access</li><li>LinkedList: Linked list implementation, fast insertion and deletion</li><li>Vector: Thread-safe ArrayList</li></ul><h3 id="set" tabindex="-1">Set <a class="header-anchor" href="#set" aria-label="Permalink to “Set”">​</a></h3><ul><li>HashSet: Based on HashMap</li><li>TreeSet: Ordered collection</li><li>LinkedHashSet: Maintains insertion order</li></ul><h3 id="map" tabindex="-1">Map <a class="header-anchor" href="#map" aria-label="Permalink to “Map”">​</a></h3><ul><li>HashMap: Hash table implementation</li><li>TreeMap: Red-black tree implementation</li><li>LinkedHashMap: Maintains insertion order</li><li>ConcurrentHashMap: Thread-safe</li></ul><h3 id="iterators" tabindex="-1">Iterators <a class="header-anchor" href="#iterators" aria-label="Permalink to “Iterators”">​</a></h3><ul><li>Iterator interface</li><li>for-each loop</li><li>Stream API</li></ul><h2 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to “Common Issues”">​</a></h2><p>Record problems encountered during learning and usage here.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li>Add source code analysis</li><li>Add performance comparisons</li><li>Add common interview questions</li></ul><h2 id="work-in-progress" tabindex="-1">Work in Progress <a class="header-anchor" href="#work-in-progress" aria-label="Permalink to “Work in Progress”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Work in Progress</p><p>This page is still being improved. More project-based examples and troubleshooting notes will be added later.</p></div>',20)])])}const u=a(o,[["render",n]]);export{m as __pageData,u as default};
